/* style.css */
h1 {
  color: #1A6FD4;
  font-size: 36px;
  text-align: center;
}

p {
  color: #555555;
  font-size: 16px;
  line-height: 1.6;
}

/* Etiket seçici */
p { color: #333; }

/* Class seçici */
.vurgu { color: red; font-weight: bold; }

/* ID seçici */
#baslik { font-size: 32px; text-align: center; }

/* Birden fazla */
h1, h2, h3 { font-family: Arial; }

/* İçindeki eleman */
.kart p { margin: 10px; }

/* Renk formatları */
.isim  { color: red; }
.hex   { color: #1A6FD4; }
.rgb   { color: rgb(26, 111, 212); }
.rgba  { color: rgba(0, 0, 0, 0.5); }

/* Tipografi */
.yazi {
  font-family: 'Arial', sans-serif;
  font-size: 18px;
  font-weight: bold;
  font-style: italic;
  letter-spacing: 2px;
  line-height: 1.8;
  text-align: center;
  text-decoration: underline;
  text-transform: uppercase;
}

* {
  box-sizing: border-box;
}

.kutu {
  width: 300px;
  height: 150px;
  padding: 20px;
  border: 2px solid #1A6FD4;
  border-radius: 12px;
  margin: 20px auto;
  background-color: #E8F0FF;
}

/* Display */
.block   { display: block; }
.inline  { display: inline; }
.inline-block { display: inline-block; }
.none    { display: none; } /* Gizle */

/* Position */
.relative {
  position: relative;
  top: 10px;
  left: 20px;
}

.absolute {
  position: absolute;
  top: 0;
  right: 0;
}

.fixed {
  position: fixed;
  bottom: 20px;
  right: 20px;
}

/* Flex container */
.menu {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 16px;
  padding: 12px;
  background: #1A6FD4;
}

/* Flex child */
.kart-alani {
  display: flex;
  flex-wrap: wrap;
  gap: 16px;
}

.kart {
  flex: 1;
  min-width: 150px;
  padding: 16px;
  background: #F0F4FF;
  border-radius: 12px;
}

/* 3 eşit sütun */
.galeri {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
}

/* Sayfa layout */
.sayfa {
  display: grid;
  grid-template-columns: 250px 1fr;
  grid-template-rows: 60px 1fr 40px;
  grid-template-areas:
    "header  header"
    "sidebar icerik"
    "footer  footer";
  min-height: 100vh;
}

.header  { grid-area: header; }
.sidebar { grid-area: sidebar; }
.icerik  { grid-area: icerik; }
.footer  { grid-area: footer; }

/* Transition — hover efekti */
.buton {
  background: #1A6FD4;
  color: white;
  padding: 12px 24px;
  border-radius: 8px;
  border: none;
  transition: all 0.3s ease;
  cursor: pointer;
}

.buton:hover {
  background: #0F2444;
  transform: translateY(-3px);
  box-shadow: 0 8px 20px rgba(26,111,212,0.4);
}

/* Keyframe animasyon */
@keyframes zipla {
  0%   { transform: translateY(0); }
  50%  { transform: translateY(-20px); }
  100% { transform: translateY(0); }
}

.ziplayan {
  animation: zipla 1s ease-in-out infinite;
}
